#{code}
) OR EXISTS ( SELECT 1 FROM admin_user_group aug JOIN admin_permission_group apg ON apg.group_code = aug.group_code AND apg.active = 1 JOIN admin_permission_group_item agi ON agi.group_code = aug.group_code JOIN admin_permission_policy app2 ON app2.permission_code = agi.permission_code AND app2.active = 1 WHERE aug.user_id = u.id AND aug.revoked_at IS NULL AND agi.permission_code IN
#{code}
) ))
OR u.role = 'ADMIN'
) AND NOT EXISTS ( SELECT 1 FROM notification_preference np WHERE np.user_id = u.id AND JSON_UNQUOTE(JSON_EXTRACT( np.categories_json, CONCAT('$."', #{optOutKey}, '"'))) = 'false' ) ORDER BY u.id
